#!/usr/bin/env node
/**
 * Generate public/llms.txt – a concise, LLM-friendly index of SSW Rules.
 *
 * The output lists categories grouped by top-category, with rule counts.
 * Individual rules are NOT listed (keeps the file ~15-20 KB instead of ~500 KB).
 *
 * Expected workspace layout (relative to repo root):
 *   category-uri-title-map.json          – generated by build-rule-category-map.py
 *   rule-to-categories.json              – generated by build-rule-category-map.py
 *   content/categories/                  – checked-out SSW.Rules.Content
 *   content/public/uploads/rules/        – rule MDX files
 *
 * Usage:
 *   node generate-llms-txt.js [content-dir]
 *
 * The content directory is resolved in order:
 *   1. CLI argument (process.argv[2])
 *   2. CONTENT_DIR env var
 *   3. Default: content/ (relative to repo root)
 *
 * Output:
 *   public/llms.txt
 */

const fs = require("node:fs");
const path = require("node:path");

// ── Path setup ────────────────────────────────────────────────────────────────
const REPO_ROOT = path.resolve(__dirname, "..");

const CATEGORY_MAP_FILE = path.join(REPO_ROOT, "category-uri-title-map.json");
const RULE_CATEGORY_FILE = path.join(REPO_ROOT, "rule-to-categories.json");
const CONTENT_DIR =
  process.argv[2] ||
  process.env.CONTENT_DIR ||
  path.join(REPO_ROOT, "content");
const CATEGORIES_DIR = path.join(CONTENT_DIR, "categories");
const RULES_DIR = path.join(CONTENT_DIR, "public", "uploads", "rules");
const OUTPUT_FILE = path.join(REPO_ROOT, "public", "llms.txt");

const SITE_URL = "https://www.ssw.com.au/rules";

// ── Helpers ───────────────────────────────────────────────────────────────────

const FRONTMATTER_RE = /^---\s*\n([\s\S]*?)\n?---/;
const TITLE_RE = /^title\s*:\s*["']?(.*?)["']?\s*$/m;
const TEMPLATE_RE = /^_template\s*:\s*["']?(.*?)["']?\s*$/m;
const URI_RE = /^uri\s*:\s*["']?(.*?)["']?\s*$/m;
const ARCHIVED_VALUE_RE = /^archivedreason\s*:\s*(.+)$/im;

/**
 * Read frontmatter from an MDX file. Returns the raw frontmatter string or null.
 */
function readFrontmatter(filePath) {
  if (!fs.existsSync(filePath)) return null;

  const fd = fs.openSync(filePath, "r");
  const buffer = Buffer.alloc(8192);
  const bytesRead = fs.readSync(fd, buffer, 0, 8192, 0);
  fs.closeSync(fd);

  const content = buffer.toString("utf-8", 0, bytesRead);
  const match = content.match(FRONTMATTER_RE);
  return match ? match[1] : null;
}

/**
 * Extract a regex match from frontmatter, stripping surrounding quotes.
 */
function extractField(frontmatter, regex) {
  const match = frontmatter.match(regex);
  if (!match) return null;
  return match[1].trim().replace(/^["']|["']$/g, "");
}

/**
 * Parse category references from a top-category's index field.
 * Matches lines like:   - category: categories/ai/rules-to-better-ai.mdx
 * Returns an array of relative paths.
 */
function parseIndexReferences(filePath, fieldName) {
  if (!fs.existsSync(filePath)) return [];

  const content = fs.readFileSync(filePath, "utf-8");
  const fmMatch = content.match(FRONTMATTER_RE);
  if (!fmMatch) return [];

  const frontmatter = fmMatch[1];
  const refs = [];
  const re = new RegExp(`^\\s*-\\s*${fieldName}\\s*:\\s*(.+)$`, "gm");
  let m;
  while ((m = re.exec(frontmatter)) !== null) {
    refs.push(m[1].trim().replace(/^["']|["']$/g, ""));
  }
  return refs;
}

/**
 * Check if a rule is archived.
 */
function isRuleArchived(ruleUri) {
  const mdxPath = path.join(RULES_DIR, ruleUri, "rule.mdx");
  const fm = readFrontmatter(mdxPath);
  if (!fm) return true; // treat missing as archived

  const arMatch = fm.match(ARCHIVED_VALUE_RE);
  if (!arMatch) return false;

  const value = arMatch[1].trim().replace(/^["']|["']$/g, "").toLowerCase();
  return value !== "null" && value !== "";
}

// ── Main ──────────────────────────────────────────────────────────────────────

function main() {
  // Load mapping files
  const categoryMap =
    JSON.parse(fs.readFileSync(CATEGORY_MAP_FILE, "utf-8")).categories || {};

  const ruleToCategoriesRaw = JSON.parse(
    fs.readFileSync(RULE_CATEGORY_FILE, "utf-8"),
  );

  // Count active rules per category
  const categoryRuleCount = {};
  for (const cat of Object.keys(categoryMap)) {
    categoryRuleCount[cat] = 0;
  }

  let totalActiveRules = 0;
  for (const [ruleUri, categories] of Object.entries(ruleToCategoriesRaw)) {
    if (isRuleArchived(ruleUri)) continue;
    totalActiveRules++;
    for (const catUri of categories) {
      if (catUri in categoryRuleCount) {
        categoryRuleCount[catUri]++;
      }
    }
  }

  // Discover top-category index files: content/categories/*/index.mdx
  const topCategoryDirs = fs
    .readdirSync(CATEGORIES_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name);

  // Build ordered list of top-categories with their child categories
  const topCategories = [];

  for (const dirName of topCategoryDirs) {
    const indexPath = path.join(CATEGORIES_DIR, dirName, "index.mdx");
    const fm = readFrontmatter(indexPath);
    if (!fm) continue;

    const template = extractField(fm, TEMPLATE_RE);
    if (template !== "top_category") continue;

    const title = extractField(fm, TITLE_RE);
    const uri = extractField(fm, URI_RE);
    if (!title) continue;

    // Parse child category references
    const catRefs = parseIndexReferences(indexPath, "category");

    const children = [];
    for (const ref of catRefs) {
      // ref looks like: categories/ai/rules-to-better-ai.mdx
      const catMdxPath = path.join(CONTENT_DIR, ref);
      const catFm = readFrontmatter(catMdxPath);
      if (!catFm) continue;

      const catTitle = extractField(catFm, TITLE_RE);
      const catUri = extractField(catFm, URI_RE);
      if (!catTitle || !catUri) continue;

      const ruleCount = categoryRuleCount[catUri] || 0;
      if (ruleCount === 0) continue;

      children.push({ title: catTitle, uri: catUri, ruleCount });
    }

    if (children.length === 0) continue;

    topCategories.push({ title, uri, children });
  }

  // Sort top-categories alphabetically by title
  topCategories.sort((a, b) => a.title.localeCompare(b.title));

  // Generate llms.txt
  const lines = [
    "# SSW Rules",
    "> Secret Ingredients to Quality Software – best practices for software development and project management.",
    `> ${totalActiveRules.toLocaleString()} rules across ${topCategories.length} topics at ${SITE_URL}/`,
    "",
  ];

  let categoriesWritten = 0;

  for (const tc of topCategories) {
    lines.push(`## [${tc.title}](${SITE_URL}/${tc.uri}/)`);
    lines.push("");

    for (const child of tc.children) {
      const plural = child.ruleCount === 1 ? "rule" : "rules";
      lines.push(
        `- [${child.title}](${SITE_URL}/${child.uri}/): ${child.ruleCount} ${plural}`,
      );
      categoriesWritten++;
    }

    lines.push("");
  }

  // Write output
  fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, lines.join("\n"), "utf-8");

  const sizeKB = (Buffer.byteLength(lines.join("\n"), "utf-8") / 1024).toFixed(1);

  console.log("✅  public/llms.txt generated");
  console.log(`   Top-categories          : ${topCategories.length}`);
  console.log(`   Categories listed        : ${categoriesWritten}`);
  console.log(`   Active rules (total)     : ${totalActiveRules}`);
  console.log(`   File size                : ${sizeKB} KB`);
}

// ── Entry point ───────────────────────────────────────────────────────────────

if (!fs.existsSync(CATEGORIES_DIR)) {
  console.error(
    `ERROR: categories directory not found: ${CATEGORIES_DIR}`,
  );
  console.error(
    "Run this script after the content repo has been checked out to ./content",
  );
  process.exit(1);
}

main();
